#!/usr/bin/env python3
"""
DreamServer PR Analyzer - Processes all 75 open PRs and generates audit data.
"""

import json
import subprocess
import os
import re
from pathlib import Path
from collections import defaultdict

REPO_DIR = Path("/workspace/dreamserver-repo")
AUDIT_DIR = Path("/workspace/dreamserver-audit")
DIFFS_DIR = Path("/tmp/pr_diffs")

def get_pr_data():
    """Load PR data from the cached API response."""
    with open("/tmp/prs_page1.json") as f:
        return json.load(f)

def parse_diff(pr_num):
    """Parse a git diff to extract changed files and stats."""
    diff_path = DIFFS_DIR / f"pr-{pr_num}.diff"
    if not diff_path.exists():
        return None

    content = diff_path.read_text()

    files_changed = []
    additions = 0
    deletions = 0

    # Parse file headers
    for line in content.split('\n'):
        if line.startswith('diff --git'):
            # Extract file paths
            parts = line.split(' ')
            if len(parts) >= 4:
                old_path = parts[2].lstrip('a/')
                new_path = parts[3].lstrip('b/')
                files_changed.append(new_path)
        elif line.startswith('@@ '):
            # Count additions/deletions from hunk headers
            match = re.search(r'\+(\d+)(?:,\d+)?', line)
            if match and '+' in line.split('@@')[1]:
                pass  # We'll count from the summary line instead

    # Parse summary line (last line of diff-stat style output)
    # Actually let's count from the diff content directly
    for line in content.split('\n'):
        if line.startswith('+') and not line.startswith('+++'):
            additions += 1
        elif line.startswith('-') and not line.startswith('---'):
            deletions += 1

    return {
        'files': files_changed,
        'additions': additions,
        'deletions': deletions,
        'total_lines': additions + deletions,
        'raw_diff': content
    }

def categorize_file(filepath):
    """Categorize a file path into a subsystem."""
    if not filepath:
        return 'unknown'

    fp = filepath.lower()

    if '/dream-host-agent.py' in fp:
        return 'host-agent'
    elif '/dashboard-api/' in fp:
        return 'dashboard-api'
    elif '/dashboard/src/' in fp:
        return 'dashboard-ui'
    elif '/dream-cli' in fp or '/lib/' in fp and 'dream-cli' in fp:
        return 'dream-cli'
    elif '/install' in fp and ('.sh' in fp or '.ps1' in fp):
        return 'installer'
    elif '/extensions/' in fp or '/extensions-library/' in fp:
        return 'extensions'
    elif '/scripts/' in fp:
        return 'scripts'
    elif '/.github/' in fp:
        return 'ci-cd'
    elif '/.env' in fp:
        return 'config'
    elif '/docker-compose' in fp:
        return 'compose'
    elif '/docs/' in fp or fp.endswith('.md'):
        return 'docs'
    elif '/tests/' in fp or fp.startswith('test'):
        return 'tests'
    elif '/resources/' in fp:
        return 'resources'
    elif '/installer/' in fp:
        return 'installer'
    elif '/bin/' in fp:
        return 'bin'
    elif '/lib/' in fp:
        return 'lib'

    return 'other'

def get_subsystems(pr_num, diff_data):
    """Get all subsystems touched by a PR."""
    if not diff_data:
        return set()
    return set(categorize_file(f) for f in diff_data['files'])

def analyze_bounty_tier(pr_body, title):
    """Try to determine the bounty tier from PR description."""
    if not pr_body:
        return 'unknown'

    body_lower = pr_body.lower()
    title_lower = title.lower() if title else ''

    if 'large' in body_lower or 'large' in title_lower:
        return 'large'
    elif 'medium' in body_lower or 'medium' in title_lower:
        return 'medium'
    elif 'small' in body_lower or 'small' in title_lower:
        return 'small'

    return 'not-specified'

def main():
    prs = get_pr_data()

    # Build comprehensive PR analysis
    pr_analysis = {}
    subsystem_map = defaultdict(list)  # subsystem -> [pr_numbers]
    contributor_map = defaultdict(list)  # contributor -> [pr_numbers]

    for pr in prs:
        num = pr['number']
        author = pr['user']['login']
        title = pr['title']
        body = pr.get('body', '') or ''

        diff_data = parse_diff(num)
        subsystems = get_subsystems(num, diff_data)

        pr_info = {
            'number': num,
            'title': title,
            'author': author,
            'body': body,
            'created_at': pr['created_at'],
            'updated_at': pr['updated_at'],
            'labels': [l['name'] for l in pr.get('labels', [])],
            'diff_data': diff_data,
            'subsystems': list(subsystems),
            'files_changed': diff_data['files'] if diff_data else [],
            'additions': diff_data['additions'] if diff_data else 0,
            'deletions': diff_data['deletions'] if diff_data else 0,
            'total_lines': diff_data['total_lines'] if diff_data else 0,
            'bounty_tier': analyze_bounty_tier(body, title),
        }

        pr_analysis[num] = pr_info

        for sub in subsystems:
            subsystem_map[sub].append(num)
        contributor_map[author].append(num)

    # Save analysis
    # Remove raw_diff from saved data (too large)
    for num in pr_analysis:
        pr_analysis[num]['diff_data'] = None  # We have the diff files

    with open(AUDIT_DIR / 'analysis' / 'pr_analysis.json', 'w') as f:
        json.dump(pr_analysis, f, indent=2, default=str)

    # Print summary
    print(f"Analyzed {len(pr_analysis)} PRs")
    print(f"\nSubsystems touched:")
    for sub, nums in sorted(subsystem_map.items(), key=lambda x: -len(x[1])):
        print(f"  {sub}: {len(nums)} PRs ({', '.join(str(n) for n in sorted(nums))})")

    print(f"\nContributors:")
    for author, nums in sorted(contributor_map.items(), key=lambda x: -len(x[1])):
        print(f"  {author}: {len(nums)} PRs ({', '.join(str(n) for n in sorted(nums))})")

    # Identify potential conflicts (PRs touching same files)
    file_to_prs = defaultdict(list)
    for num, info in pr_analysis.items():
        for f in info['files_changed']:
            file_to_prs[f].append(num)

    conflicts = {f: nums for f, nums in file_to_prs.items() if len(nums) > 1}
    print(f"\nFiles touched by multiple PRs ({len(conflicts)} files):")
    for f, nums in sorted(conflicts.items(), key=lambda x: -len(x[1]))[:20]:
        print(f"  {f}: PRs {nums}")

if __name__ == '__main__':
    main()
